class Solution:
    def longestSemiRepetitiveSubstring(self, s: str) -> int:
        max_len = 1
        n = len(s)
        for i in range(n):
            for j in range(i + 1, n):
                substr = s[i:j + 1]
                if self.is_semi_repetitive(substr):
                    max_len = max(max_len, j - i + 1)
        return max_len

    def is_semi_repetitive(self, t: str) -> bool:
        count = 0
        for i in range(len(t) - 1):
            if t[i] == t[i + 1]:
                count += 1
                if count > 1:
                    return False
        return True
